#include <bits/stdc++.h>
#define int long long
#define MAX_N 200010
using namespace std;
struct tree {
    vector <int> nxt;
    vector <int> nextw1;
    vector <int> nextw2;
} node[MAX_N];
int n;
int d[MAX_N], f[MAX_N][21], disw1[MAX_N], disw2[MAX_N];
int num[MAX_N], ans[MAX_N];
void bfs (int v){
    queue <int> q;
    d[v] = 1;
    q.push (v);
    int t = (int)(log (n) / log (2)) + 1;
    while (!q.empty ()){
        int u = q.front ();
        q.pop ();
        for (int i = 0; i < node[u].nxt.size (); i++) {
            int y = node[u].nxt[i];
            if (d[y] != 0) {
				continue;
			}
            d[y] = d[u] + 1;
            f[y][0] = u;
            int w1 = node[u].nextw1[i];
            int w2 = node[u].nextw2[i];
            disw1[y] = w1;
            disw2[y] = w2;
            for (int j = 1; j <= t; j++) {
                f[y][j] = f[f[y][j - 1]][j - 1];
            }
            q.push (y);
        }
    }
    return ; 
}
int LCA (int x, int y) {
    int t = (log(n) / log(2)) + 1;
    if (d[x] > d[y]) {
        swap (x, y);
    }
    for (int i = t; i >= 0; i--) {
        if (d[f[y][i]] >= d[x]) {
            y = f[y][i];
        }
    }
    if (x == y) {
		return x;
	}
    for (int i = t; i >= 0; i--) {
        if (f[y][i] != f[x][i]) {
            x = f[x][i];
			y = f[y][i];
		}
	}
    return f[x][0];
}
int dfs (int now, int fa) {
	ans[now] += num[now];
	for (int i = 0; i < node[now].nxt.size (); i++) {
		int y = node[now].nxt[i];
		if (fa != y) {
			ans[now] += dfs (y, now);
		}
	}
	return ans[now];
} 
signed main() {
    cin >> n;
    for (int i = 1; i < n; i++) {
        int u, v, w1, w2;
        cin >> u >> v >> w1 >> w2;
        node[u].nxt.push_back (v);
        node[u].nextw1.push_back (w1);
        node[u].nextw2.push_back (w2);
        node[v].nxt.push_back (u);
        node[v].nextw1.push_back (w1);
        node[v].nextw2.push_back (w2);
    }
    bfs (1);
    for (int i = 2; i <= n; i++) {
    	int u = i - 1, v = i;
    	int z = LCA (u, v);
    	num[u]++;
    	num[v]++;
    	num[z] -= 2;
	}
    dfs (1, -1);
    int min_ans = 0;
    for (int i = 2; i <= n; i++) {
        int w1 = disw1[i];
        int w2 = disw2[i];
        int t = ans[i];
        min_ans += min (w1 * t, w2);
    }
    cout << min_ans;
    return 0;
}
